@@ -3349,3 +3349,277 @@ html.theme-transitioning *::after {
     transform: none;
   }
 }
+
+/* ============================================================================
+   STRIPE-LEVEL POLISH ENHANCEMENTS
+   Additional micro-interactions and visual refinements
+   ============================================================================ */
+
+/* --- TYPOGRAPHY OPTICAL ADJUSTMENTS --- */
+/* Larger text needs tighter letter-spacing for visual balance */
+.text-4xl, .text-5xl, .text-6xl {
+  letter-spacing: -0.025em;
+}
+
+.text-3xl {
+  letter-spacing: -0.02em;
+}
+
+.text-2xl {
+  letter-spacing: -0.015em;
+}
+
+.text-xl {
+  letter-spacing: -0.01em;
+}
+
+/* Fluid heading with optical adjustments */
+.heading-display {
+  font-weight: 700;
+  letter-spacing: -0.03em;
+  line-height: 1.1;
+  text-wrap: balance;
+}
+
+/* Subheading with refined tracking */
+.heading-section {
+  font-weight: 600;
+  letter-spacing: -0.015em;
+  line-height: 1.2;
+}
+
+/* Body text optimized for reading */
+.text-body {
+  font-size: 1rem;
+  line-height: 1.7;
+  letter-spacing: 0.01em;
+}
+
+/* Caption/metadata text */
+.text-caption {
+  font-size: 0.75rem;
+  letter-spacing: 0.02em;
+  color: var(--muted-foreground);
+}
+
+/* --- ENHANCED SKELETON LOADING --- */
+/* Premium shimmer effect with smooth gradient sweep */
+@keyframes skeleton-shimmer-premium {
+  0% {
+    transform: translateX(-100%);
+  }
+  100% {
+    transform: translateX(100%);
+  }
+}
+
+.skeleton-premium {
+  position: relative;
+  overflow: hidden;
+  background: linear-gradient(
+    90deg,
+    var(--skeleton-base) 0%,
+    var(--skeleton-base) 100%
+  );
+  border-radius: var(--radius);
+}
+
+.skeleton-premium::after {
+  content: "";
+  position: absolute;
+  inset: 0;
+  background: linear-gradient(
+    90deg,
+    transparent 0%,
+    var(--skeleton-shine) 20%,
+    var(--skeleton-shine) 40%,
+    transparent 100%
+  );
+  animation: skeleton-shimmer-premium 1.8s ease-in-out infinite;
+  transform: translateX(-100%);
+}
+
+/* Pulse skeleton variant */
+@keyframes skeleton-pulse {
+  0%, 100% {
+    opacity: 1;
+  }
+  50% {
+    opacity: 0.5;
+  }
+}
+
+.skeleton-pulse {
+  background: var(--skeleton-base);
+  border-radius: var(--radius);
+  animation: skeleton-pulse 2s ease-in-out infinite;
+}
+
+/* --- MOBILE TOUCH FEEDBACK REFINEMENTS --- */
+/* Enhanced touch feedback with visual confirmation */
+@media (hover: none) and (pointer: coarse) {
+  /* Touch highlight for interactive elements */
+  .touch-highlight {
+    -webkit-tap-highlight-color: rgba(var(--primary-rgb, 139, 92, 246), 0.15);
+  }
+
+  /* Active state with background flash */
+  .touch-feedback {
+    position: relative;
+    isolation: isolate;
+  }
+
+  .touch-feedback::before {
+    content: "";
+    position: absolute;
+    inset: 0;
+    background: currentColor;
+    border-radius: inherit;
+    opacity: 0;
+    transition: opacity 100ms ease-out;
+    pointer-events: none;
+    z-index: -1;
+  }
+
+  .touch-feedback:active::before {
+    opacity: 0.08;
+  }
+
+  /* Bounce feedback on tap */
+  .touch-bounce {
+    transition: transform 150ms cubic-bezier(0.34, 1.56, 0.64, 1);
+  }
+
+  .touch-bounce:active {
+    transform: scale(0.95);
+  }
+}
+
+/* --- FOCUS ENHANCEMENTS --- */
+/* Animated focus ring for premium feel */
+@keyframes focus-ring-pulse {
+  0%, 100% {
+    box-shadow: 0 0 0 2px var(--background), 0 0 0 4px var(--ring);
+  }
+  50% {
+    box-shadow: 0 0 0 2px var(--background), 0 0 0 5px var(--ring), 0 0 12px var(--ring);
+  }
+}
+
+.focus-ring-animated:focus-visible {
+  outline: none;
+  animation: focus-ring-pulse 1.5s ease-in-out infinite;
+}
+
+/* Subtle focus indicator for dense UIs */
+.focus-subtle:focus-visible {
+  outline: none;
+  box-shadow: inset 0 0 0 1px var(--ring);
+}
+
+/* --- INTERACTIVE DEPTH --- */
+/* Elements that respond to hover with depth changes */
+.depth-interactive {
+  transition:
+    transform 200ms cubic-bezier(0.25, 0.1, 0.25, 1),
+    box-shadow 200ms cubic-bezier(0.25, 0.1, 0.25, 1);
+}
+
+.depth-interactive:hover {
+  transform: translateY(-2px);
+  box-shadow:
+    0 4px 6px -1px rgba(0, 0, 0, 0.05),
+    0 10px 15px -3px rgba(0, 0, 0, 0.08);
+}
+
+.depth-interactive:active {
+  transform: translateY(0);
+  box-shadow:
+    0 1px 2px rgba(0, 0, 0, 0.04),
+    0 1px 3px rgba(0, 0, 0, 0.06);
+  transition-duration: 75ms;
+}
+
+.dark .depth-interactive:hover {
+  box-shadow:
+    0 4px 6px -1px rgba(0, 0, 0, 0.2),
+    0 10px 15px -3px rgba(0, 0, 0, 0.3);
+}
+
+/* --- BUTTON GLOW PULSE --- */
+/* Attention-grabbing glow animation for primary CTAs */
+@keyframes button-glow-pulse {
+  0%, 100% {
+    box-shadow:
+      0 1px 2px rgba(0, 0, 0, 0.05),
+      0 0 20px rgba(var(--primary-rgb, 139, 92, 246), 0.15);
+  }
+  50% {
+    box-shadow:
+      0 1px 2px rgba(0, 0, 0, 0.05),
+      0 0 30px rgba(var(--primary-rgb, 139, 92, 246), 0.25);
+  }
+}
+
+.button-glow-pulse {
+  animation: button-glow-pulse 2s ease-in-out infinite;
+}
+
+/* --- SMOOTH SCROLL SNAP --- */
+/* Premium scroll snapping for carousels */
+.scroll-snap-x {
+  scroll-snap-type: x mandatory;
+  scroll-behavior: smooth;
+  -webkit-overflow-scrolling: touch;
+}
+
+.scroll-snap-item {
+  scroll-snap-align: start;
+  scroll-snap-stop: always;
+}
+
+.scroll-snap-center {
+  scroll-snap-align: center;
+}
+
+/* --- CONTENT VISIBILITY OPTIMIZATION --- */
+/* Improve rendering performance for off-screen content */
+.content-visibility-auto {
+  content-visibility: auto;
+  contain-intrinsic-size: 0 500px;
+}
+
+/* --- SUBTLE GRAIN OVERLAY --- */
+/* Adds tactile texture to surfaces */
+.grain-subtle::before {
+  content: "";
+  position: absolute;
+  inset: 0;
+  background-image: url("data:image/svg+xml,%3Csvg viewBox='0 0 200 200' xmlns='http://www.w3.org/2000/svg'%3E%3Cfilter id='noise'%3E%3CfeTurbulence type='fractalNoise' baseFrequency='0.65' numOctaves='3' stitchTiles='stitch'/%3E%3C/filter%3E%3Crect width='100%25' height='100%25' filter='url(%23noise)'/%3E%3C/svg%3E");
+  opacity: 0.015;
+  pointer-events: none;
+  mix-blend-mode: overlay;
+  border-radius: inherit;
+}
+
+.dark .grain-subtle::before {
+  opacity: 0.03;
+}
+
+/* --- BORDER GRADIENT UTILITY --- */
+/* Apply gradient borders to any element */
+.border-gradient {
+  position: relative;
+  background-clip: padding-box;
+  border: 1px solid transparent;
+}
+
+.border-gradient::before {
+  content: "";
+  position: absolute;
+  inset: 0;
+  z-index: -1;
+  margin: -1px;
+  border-radius: inherit;
+  background: linear-gradient(135deg, var(--primary), var(--accent));
+}
